(function ($, Drupal, drupalSettings) {

  'use strict';

  Drupal.behaviors.minimalShare = {
    attach: function (context) {
      $('.minimal-share a', context).once('minimal-share').each(function () {
        var $this = $(this);
        var size = false;
        var provider = $this.data('ms');

        if (drupalSettings.minimalShare.sizes[provider]) {
          size = drupalSettings.minimalShare.sizes[provider];
        }

        // Show hidden mobile share links.
        if ($this.hasClass('ms-mobile-only') && (('ontouchstart' in window) || window.DocumentTouch && document instanceof DocumentTouch)) {
          $this.addClass('ms-show');
        }

        $this.bind('click', function (e) {
          if (provider === 'print') {
            window.print();
            e.preventDefault();
          }
          else if (size) {
            var width = size.width;
            var height = size.height;
            var url = $this.attr('href');
            var wx = (screen.width - width) >> 1;
            var wy = (screen.height - height) >> 1;

            window.open(url, '', 'top=' + wy + ',left=' + wx + ',width=' + width + ',height=' + height);

            e.preventDefault();
            e.stopPropagation();
          }
        });
      });
    }
  };

})(jQuery, Drupal, drupalSettings);
;
/**
 * @file
 * Adds radioactivity triggers.
 */

(function ($, Drupal, drupalSettings) {

  'use strict';

  /**
   * Add Radioactivity triggers.
   */
  Drupal.behaviors.radioactivityTriggers = {
    attach: function (context) {
      // Only run on page load, not for subsequent ajax loads.
      if (typeof context == 'object' && context.toString().indexOf('HTMLDocument') != -1) {
        var emits = [], emit, i = 0;

        while (emit = drupalSettings['ra_emit_' + i]) {
          emits.push(JSON.parse(emit));
          i++;
        }

        $.ajax({
          type: "POST",
          url: drupalSettings.radioactivity.endpoint,
          data: JSON.stringify(emits),
          success: function (data) {
            if (data.status != 'ok') {
              console.error('Radioactivity: ' + data.message);
            }
          },
          dataType: 'json'
        });

      }
    }
  }
})(jQuery, Drupal, drupalSettings);
